import React from 'react';

const NotificationBadge = ({ count }) => {
  // Ensure count is a non-negative number
  const validCount = Math.max(0, count);
  const displayCount = validCount > 99 ? '99+' : String(validCount);

  return (
    <div style={{ position: 'relative', display: 'inline-block', fontSize: '24px' }}>
      <span role="img" aria-label={`Notifications: ${validCount} unread`}>
        🔔
      </span>
      {validCount > 0 && (
        <span
          style={{
            position: 'absolute',
            top: '-5px',
            right: '-10px',
            backgroundColor: 'red',
            color: 'white',
            borderRadius: '50%',
            padding: '2px 6px',
            fontSize: '12px',
            fontWeight: 'bold',
            minWidth: '18px',
            textAlign: 'center',
            lineHeight: '14px',
            boxSizing: 'border-box',
            border: '1px solid white' // Added for better visibility on some backgrounds
          }}
          aria-live="polite" // Announce changes to screen readers
        >
          {displayCount}
        </span>
      )}
    </div>
  );
};

export default NotificationBadge;

