  <div id="app">
    <h1>Notification Badge Demo</h1>
    <div class="demo-row">
      <NotificationBadge :count="0" />
      <span>No notifications</span>
    </div>
    <div class="demo-row">
      <NotificationBadge :count="1" />
      <span>1 notification</span>
    </div>
    <div class="demo-row">
      <NotificationBadge :count="15" />
      <span>15 notifications</span>
    </div>
    <div class="demo-row">
      <NotificationBadge :count="105" />
      <span>105 notifications</span>
    </div>
  </div>
</template>

<script setup>
import NotificationBadge from './components/NotificationBadge.vue';
</script>

<style>
#app {
  font-family: Avenir, Helvetica, Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-align: center;
  color: #2c3e50;
  margin-top: 60px;
}

.demo-row {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 15px;
  margin-bottom: 20px;
}

.demo-row span {
